package com.chaobo.scm.supplier.application.qualification;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.shared.*;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import com.chaobo.scm.supplier.infrastructure.persistence.qualification.QualificationRequirementMapper;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.*;
@Service public class QualificationRequirementApplicationService {private final QualificationRequirementMapper mapper;private final IdentifierGenerator ids;private final AuditLogRepository audit;public QualificationRequirementApplicationService(QualificationRequirementMapper mapper,IdentifierGenerator ids,AuditLogRepository audit){this.mapper=mapper;this.ids=ids;this.audit=audit;}@Transactional(readOnly=true)public List<View> list(){return mapper.list().stream().map(this::view).toList();}@Transactional public long create(String supplierType,Long categoryId,String type,boolean mandatory,CommandContext c){c.requirePermission("supplier:qualification-rule:manage");valid(type);long id=ids.nextId();mapper.insert(new QualificationRequirementMapper.Row(id,blank(supplierType),categoryId,type,mandatory,1,0),c.operatorId());audit.save(c,"CREATE_QUALIFICATION_REQUIREMENT","QUALIFICATION_REQUIREMENT",id,type,null,"{\"status\":1}");return id;}@Transactional public void update(long id,int version,String supplierType,Long categoryId,String type,boolean mandatory,int status,CommandContext c){c.requirePermission("supplier:qualification-rule:manage");valid(type);if(status<1||status>2)throw rule("规则状态不合法");if(mapper.update(new QualificationRequirementMapper.Row(id,blank(supplierType),categoryId,type,mandatory,status,version),version,c.operatorId())!=1)throw new BusinessException(ErrorCode.VERSION_CONFLICT,"资质规则已更新");audit.save(c,"UPDATE_QUALIFICATION_REQUIREMENT","QUALIFICATION_REQUIREMENT",id,type,null,"{\"status\":"+status+"}");}private View view(QualificationRequirementMapper.Row r){return new View(r.id(),r.supplierType(),r.categoryId(),r.qualificationType(),r.mandatory(),r.status(),r.version());}private static void valid(String type){if(type==null||type.isBlank())throw rule("资质类型不能为空");}private static String blank(String value){return value==null||value.isBlank()?null:value.trim();}private static BusinessException rule(String message){return new BusinessException(ErrorCode.VALIDATION_FAILED,message);}public record View(long id,String supplierType,Long categoryId,String qualificationType,boolean mandatory,int status,int version){}}
